@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #efeff1;
  --color-neutral-200: #d9d8dd;
  --color-neutral-300: #c8c8d0;
  --color-neutral-400: #b7b2a7;
  --color-neutral-500: #adadb8;
  --color-neutral-600: #848494;
  --color-neutral-700: #808080;
  --color-neutral-800: #53535f;
  --color-neutral-900: #26262c;
  --color-neutral-950: #0e0e10;
  --color-indigo: #9147ff;
  --color-indigo-2: #772ce8;
  --color-indigo-3: #5c16c5;
  --color-indigo-4: #a970ff;
  --color-indigo-5: #bf94ff;
  --color-blue: #1e69ff;
  --color-purple: #8205b4;
  --color-yellow: #e2be53;
  --color-blue-2: #3b5998;
  --color-purple-2: #f093f9;
  --color-yellow-2: #976700;
  --color-yellow-3: #fafa19;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #0e0e10;
  --color-text-muted: #adadb8;
  --color-surface: #efeff1;
  --color-hairline: #d9d8dd;
  --color-accent: #9147ff;
  --color-accent-2: #772ce8;
  --color-accent-3: #5c16c5;

  --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 1rem;
  --text-sm: 1.125rem;
  --text-base: 1.2rem;
  --text-lg: 1.6rem;

  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1.5;
  --leading-tight: 1.7;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: .1em;

  --radius-sm: 2px;
  --radius-md: 5px;
  --radius-lg: .4rem;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 3px 10px -2px;

  --breakpoint-sm: 47.9375rem;
  --breakpoint-md: 48rem;
  --breakpoint-lg: 57.4375rem;
  --breakpoint-xl: 57.5rem;
  --breakpoint-2xl: 63.9375rem;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 5, 8, 10, 16, 21, 24, 32, 160 */
}

